"use client";

import { useEffect, useRef, useState } from "react";
import Container from "@/components/primitives/Container";
import ChatHeader from "./ChatHeader";
import ChatMessageList from "./ChatMessageList";
import ChatInput from "./ChatInput";
import { useChat } from "./useChat";

export default function ChatSurface() {
  const chat = useChat();
  const [draft, setDraft] = useState("");
  const isStreaming = chat.status === "streaming";
  const surfaceRef = useRef<HTMLDivElement | null>(null);

  // Mark this page so the global SiteFooter can hide itself.
  useEffect(() => {
    const prev = document.body.dataset.page;
    document.body.dataset.page = "chat";
    return () => {
      if (prev === undefined) delete document.body.dataset.page;
      else document.body.dataset.page = prev;
    };
  }, []);

  // Mirror visualViewport.height onto a CSS variable on the surface so
  // children (input row, message list) can size themselves against the
  // post-keyboard viewport on iOS without duplicating listeners.
  useEffect(() => {
    if (typeof window === "undefined") return;
    const vv = window.visualViewport;
    if (!vv) return;
    const el = surfaceRef.current;
    if (!el) return;

    function update() {
      if (!el || !vv) return;
      el.style.setProperty("--chat-vv-height", `${vv.height}px`);
    }
    update();
    vv.addEventListener("resize", update);
    vv.addEventListener("scroll", update);
    return () => {
      vv.removeEventListener("resize", update);
      vv.removeEventListener("scroll", update);
    };
  }, []);

  function handleSubmit() {
    const value = draft;
    setDraft("");
    void chat.submit(value);
  }

  return (
    <Container
      ref={surfaceRef}
      size="narrow"
      as="section"
      className="chat-surface"
    >
      <ChatHeader
        onClear={chat.clear}
        hasMessages={chat.messages.length > 0}
      />
      <ChatMessageList
        messages={chat.messages}
        lastError={chat.lastError}
        onRetry={chat.retry}
      />
      <ChatInput
        value={draft}
        onChange={setDraft}
        onSubmit={handleSubmit}
        onStop={chat.stopStreaming}
        isStreaming={isStreaming}
      />
    </Container>
  );
}

